const uint16_t* parkBackground(uint8_t timeOfDay) {
    switch (timeOfDay) {
        case 1: return PARK_AFTERNOON;
        case 2: return PARK_EVENING;
        case 0:
        default: return PARK_MORNING;
    }
}

const uint16_t* background(uint8_t location, uint8_t timeOfDay) {
    switch (location) {
        case 0: return parkBackground(timeOfDay);
        case 1: return BACK_HILL_DAY;
        case 2: return timeOfDay == 2 ? RIVERSIDE_NIGHT : RIVERSIDE_DAY;
        case 3: return timeOfDay == 2 ? OLD_WOODS_NIGHT : OLD_WOODS_DAY;
        default: return nullptr;
    }
}

